import{_ as l,c as s,m as t,a,J as r,w as o,a6 as n,E as i,o as h}from"./chunks/framework.Bw_bo0GO.js";const A=JSON.parse('{"title":"机场评测","description":"","frontmatter":{},"headers":[],"relativePath":"trip/airport.md","filePath":"trip/airport.md","lastUpdated":1703742176000}'),d={name:"trip/airport.md"},c=n('<h1 id="机场评测" tabindex="-1">机场评测 <a class="header-anchor" href="#机场评测" aria-label="Permalink to &quot;机场评测&quot;">​</a></h1><p>停止安检前/停止值机前 <strong>30分钟</strong> 到达机场即可，如 17:35 值机截至，17:05 到达机场即可</p><h2 id="其他信息" tabindex="-1">其他信息 <a class="header-anchor" href="#其他信息" aria-label="Permalink to &quot;其他信息&quot;">​</a></h2><h3 id="贵宾厅" tabindex="-1">贵宾厅 <a class="header-anchor" href="#贵宾厅" aria-label="Permalink to &quot;贵宾厅&quot;">​</a></h3><p>非贵宾厅登机流程：到达机场，进入起飞大厅，值机/办理托运，国内/国际安检，候机，登机口刷机票登机，成功登机。<br> 贵宾厅登机流程（安检前的贵宾厅）：到达机场，前台出示身份证打印登机牌/办理托运，进入休息室休息，等待服务人员提醒登机，开始安检，乘坐巴士前往飞机脚下，成功入机。</p><p><strong>安检前的贵宾厅</strong>：直接到机场，找到贵宾厅。会需要你的身份证，服务人员打印登机牌。按服务员所说位置，进去休息，吃喝玩乐。完全不用担心飞机什么时候起飞，服务人员会来叫你去登机。提醒后，回带领你前往专属安检通道，无需排队。安检过后，坐上专属巴士，直达飞机阶梯下。</p><h2 id="机场列表" tabindex="-1">机场列表 <a class="header-anchor" href="#机场列表" aria-label="Permalink to &quot;机场列表&quot;">​</a></h2><h3 id="杭州萧山机场" tabindex="-1">杭州萧山机场 <a class="header-anchor" href="#杭州萧山机场" aria-label="Permalink to &quot;杭州萧山机场&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">公共交通时间计算</p><p>现在居住位置到机场，地铁总计耗时至多80分钟<br> 如果出发过早，地铁还没有发车，可以从现在的居住位置打车到文三路，至少需要16分钟<br><strong>文三路</strong> - 机场， <strong>19号线</strong>，包含发车间隔，最多需要45分钟。下地铁后，到达 T2/T3 航站楼大约需要6分钟，到达 T4 大约需要13分钟</p><p><strong>两种方案</strong><br> 只地铁 80分钟 + 10分钟步行，<strong>90m</strong> - 100m<br> 打车+地铁 65分钟 + 10分钟步行，<strong>75m</strong> - 85m</p></div><h3 id="南京禄口机场" tabindex="-1">南京禄口机场 <a class="header-anchor" href="#南京禄口机场" aria-label="Permalink to &quot;南京禄口机场&quot;">​</a></h3>',10),_=t("strong",null,"地铁",-1),p=t("strong",null,"地铁",-1),u=t("br",null,null,-1),m=t("strong",null,"高铁",-1),b=t("br",null,null,-1),f=t("strong",null,"S1机场线",-1),q=n('<h3 id="南阳姜营机场" tabindex="-1">南阳姜营机场 <a class="header-anchor" href="#南阳姜营机场" aria-label="Permalink to &quot;南阳姜营机场&quot;">​</a></h3><p>机场交通配套很差劲，原本以为跟高铁站面对面，去现场看了之后发现是背靠背，极其不方便，不推荐这个机场。</p><h3 id="上海浦东机场" tabindex="-1">上海浦东机场 <a class="header-anchor" href="#上海浦东机场" aria-label="Permalink to &quot;上海浦东机场&quot;">​</a></h3><p>浦东的交通配套不是很方便，从虹桥出发需要预留至少3小时，浪费时间。<br> 如果从杭州出发，在2023年7月及之前的时候，时间/金钱成本都很高。</p><ul><li>机场大巴：武林门/杭州东站-上海浦东，2h30m ￥130</li><li>高铁到虹桥需要转地铁，高铁￥75，地铁￥8，时间1h+1.5h</li></ul><p>期待 2024年 浦东通高铁吧。不要考虑这个机场，如果不在浦东附近的话。</p><h3 id="上海虹桥机场" tabindex="-1">上海虹桥机场 <a class="header-anchor" href="#上海虹桥机场" aria-label="Permalink to &quot;上海虹桥机场&quot;">​</a></h3><h3 id="广州白云机场" tabindex="-1">广州白云机场 <a class="header-anchor" href="#广州白云机场" aria-label="Permalink to &quot;广州白云机场&quot;">​</a></h3><p>离市区非常远，期待高铁吧，到广州南站地铁需要 80 分钟</p><h3 id="沈阳桃仙机场" tabindex="-1">沈阳桃仙机场 <a class="header-anchor" href="#沈阳桃仙机场" aria-label="Permalink to &quot;沈阳桃仙机场&quot;">​</a></h3>',10);function g(P,x,T,k,S,V){const e=i("Badge");return h(),s("div",null,[c,t("p",null,[a("家-杭州东 "),_,r(e,{type:"tip"},{default:o(()=>[a("30min")]),_:1}),a(" 家-杭州西 "),p,a(),r(e,{type:"tip"},{default:o(()=>[a("40min")]),_:1}),a("40m"),u,a(" 杭州东/杭州西-南京南 "),m,a(),r(e,{type:"tip"},{default:o(()=>[a("1h30min")]),_:1}),b,a(" 南京南-禄口机场 "),f,a(),r(e,{type:"tip"},{default:o(()=>[a("40min")]),_:1})]),q])}const C=l(d,[["render",g]]);export{A as __pageData,C as default};
